module.render:
const body = sections[0] ? sections[0].trim() : '';
const href = (args.href && String(args.href).trim()) || '#';
const color = (args.color && String(args.color).trim()) || 'var(--accent-color)';
const variant = (args.variant || 'solid').toLowerCase() === 'outline' ? 'outline' : 'solid';
const size = ['sm','md','lg'].indexOf((args.size || 'md').toLowerCase()) >= 0 ? (args.size || 'md').toLowerCase() : 'md';
const target = (args.target || '_self') === '_blank' ? '_blank' : '_self';
const radius = parseFloat(args.radius);
let style = '--btn-c: ' + color + ';';
if (variant === 'solid') style += ' background-color: ' + color + ';';
if (Number.isFinite(radius) && radius >= 0) style += ' --btn-r: ' + radius + 'px;';
const cls = 'mdp-mod-button mdp-btn-' + size + (variant === 'outline' ? ' mdp-btn-outline' : '');
const targetAttr = target === '_blank' ? ' target="_blank" rel="noopener"' : '';
return '<a class="' + cls + '" href="' + href + '"' + targetAttr + ' style="' + style + '">' + body + '</a>';
